<section class="admin-panel"><h2>New Business Submissions</h2><?php while($l=$new_locations->fetch_assoc()):$dupes=admin_duplicate_summary_for_candidate($conn,admin_location_candidate($l));?><article class="admin-list-item"><div><h3><?php echo craftcrawl_admin_escape($l['name']);?></h3><p><?php echo craftcrawl_admin_escape($l['account_email'] . ' · ' . $l['city'] . ', ' . $l['state']);?></p><p>Status: <?php echo craftcrawl_admin_escape(ucwords(str_replace('_',' ',$l['submission_review_status'])));?></p><?php if(!empty($l['submission_response_notes'])):?><p>Business response: <?php echo nl2br(craftcrawl_admin_escape($l['submission_response_notes']));?></p><?php endif;?><?php admin_render_duplicate_summary($dupes);?></div><form method="POST"><?php echo craftcrawl_csrf_input();?><input type="hidden" name="location_id" value="<?php echo $l['id'];?>"><?php if(admin_has_soft_duplicate($dupes)):?><label><input type="checkbox" name="confirm_soft_duplicate" value="1"> Create anyway after duplicate review</label><?php endif;?><textarea name="admin_notes" placeholder="Notes / request"><?php echo craftcrawl_admin_escape($l['adminNotes']??'');?></textarea><button name="form_action" value="save_location_notes">Save notes</button><button name="form_action" value="approve_new_location">Approve</button><button name="form_action" value="more_info_new_location">Request more info</button><button name="form_action" value="reject_new_location">Reject</button></form></article><?php endwhile;?></section>
