<section class="admin-panel"><h2>Pending Imported Locations</h2><?php while($l=$imports->fetch_assoc()):$dupes=admin_duplicate_summary_for_candidate($conn,admin_location_candidate($l));$full_address=trim(implode(', ',array_filter([$l['street_address'], $l['apt_suite'], $l['city'], $l['state'], $l['zip']])));?><article class="admin-list-item admin-import-review-item"><div class="admin-import-details"><h3><?php echo craftcrawl_admin_escape($l['name']);?></h3><p><?php echo craftcrawl_admin_escape(craftcrawl_admin_business_type_label($l['location_type']));?> · Mapbox import candidate</p><p><strong>Address:</strong> <?php echo craftcrawl_admin_escape($full_address);?></p><?php if(!empty($l['phone'])):?><p><strong>Phone:</strong> <?php echo craftcrawl_admin_escape($l['phone']);?></p><?php endif;?><?php if(!empty($l['website'])):?><p><strong>Website:</strong> <?php echo craftcrawl_admin_escape($l['website']);?></p><?php endif;?><p><strong>Mapbox ID:</strong> <?php echo craftcrawl_admin_escape($l['source_place_id']);?></p><?php admin_render_duplicate_summary($dupes);?></div><form class="admin-import-review-form" method="POST"><?php echo craftcrawl_csrf_input();?><input type="hidden" name="location_id" value="<?php echo $l['id'];?>"><?php if(admin_has_soft_duplicate($dupes)):?><label><input type="checkbox" name="confirm_soft_duplicate" value="1"> Approve anyway after duplicate review</label><?php endif;?><textarea name="admin_notes" placeholder="Admin notes"><?php echo craftcrawl_admin_escape($l['adminNotes']??'');?></textarea><div class="admin-import-review-actions"><button name="form_action" value="save_location_notes">Save notes</button><button name="form_action" value="approve_import">Approve public listing</button><button name="form_action" value="reject_import">Reject</button></div></form></article><?php endwhile;?></section>
<section class="admin-panel"><h2>Check-in Readiness</h2><?php while($l=$readiness->fetch_assoc()):$full_address=trim(implode(', ',array_filter([$l['street_address'], $l['apt_suite'], $l['city'], $l['state'], $l['zip']])));$hours=craftcrawl_location_hours_for_form($conn,(int)$l['id']);$hours_text=craftcrawl_business_hours_have_saved_hours($hours)?craftcrawl_format_business_hours($hours):'';$has_verified_hours=craftcrawl_location_has_verified_hours($conn,(int)$l['id']);?><article class="admin-list-item admin-readiness-review-item"><div class="admin-readiness-details"><h3><?php echo craftcrawl_admin_escape($l['name']);?></h3><p><?php echo craftcrawl_admin_escape(craftcrawl_admin_business_type_label($l['location_type']));?> · <?php echo craftcrawl_admin_escape(ucwords(str_replace('_',' ',$l['visibility_status'])));?></p><p><strong>Address:</strong> <?php echo craftcrawl_admin_escape($full_address);?></p><?php if(!empty($l['phone'])):?><p><strong>Phone:</strong> <?php echo craftcrawl_admin_escape($l['phone']);?></p><?php endif;?><?php if(!empty($l['website'])):?><p><strong>Website:</strong> <?php echo craftcrawl_admin_escape($l['website']);?></p><?php endif;?><?php if(!empty($l['source_place_id'])):?><p><strong>Mapbox ID:</strong> <?php echo craftcrawl_admin_escape($l['source_place_id']);?></p><?php endif;?><p><strong>Hours:</strong> <?php echo $has_verified_hours?'Verified':'Not verified';?></p><?php if($hours_text!==''):?><p class="admin-readiness-hours"><?php echo nl2br(craftcrawl_admin_escape($hours_text));?></p><?php endif;?></div><form class="admin-readiness-review-form" method="POST"><?php echo craftcrawl_csrf_input();?><input type="hidden" name="location_id" value="<?php echo $l['id'];?>"><textarea name="admin_notes" placeholder="Admin notes"><?php echo craftcrawl_admin_escape(($l['adminNotes']??'')!==''?$l['adminNotes']:($l['suggestion_user_notes']??''));?></textarea><div class="admin-readiness-actions"><button name="form_action" value="save_location_notes">Save notes</button><a href="location_hours.php?id=<?php echo $l['id'];?>">Edit hours</a><button name="form_action" value="enable_checkins" <?php echo $has_verified_hours?'':'disabled';?>>Enable check-ins</button><button name="form_action" value="hide_location">Hide location</button></div><?php if(!$has_verified_hours):?><p class="form-help">Verified hours are required before check-ins can be enabled.</p><?php endif;?></form></article><?php endwhile;?></section>
<section class="admin-panel"><h2>Rejected / Hidden Locations &amp; Suggestions</h2><?php while($l=$rejected_hidden->fetch_assoc()):$full_address=trim(implode(', ',array_filter([$l['street_address'], $l['apt_suite'], $l['city'], $l['state'], $l['zip']])));$is_suggestion=$l['recovery_type']==='suggestion';?><article class="admin-list-item admin-recovery-review-item"><div class="admin-recovery-details"><h3><?php echo craftcrawl_admin_escape($l['name']);?></h3><p><?php echo craftcrawl_admin_escape(craftcrawl_admin_business_type_label($l['location_type']));?> · <?php echo craftcrawl_admin_escape($is_suggestion ? 'Suggestion '.ucwords($l['review_status']) : ucwords($l['review_status']));?></p><p><strong>Address:</strong> <?php echo craftcrawl_admin_escape($full_address);?></p><?php if($is_suggestion&&!empty($l['suggested_by'])):?><p><strong>Suggested by:</strong> <?php echo craftcrawl_admin_escape($l['suggested_by']);?></p><?php endif;?><?php if($is_suggestion&&!empty($l['user_notes'])):?><p><strong>User notes:</strong> <?php echo nl2br(craftcrawl_admin_escape($l['user_notes']));?></p><?php endif;?><?php if($is_suggestion&&!empty($l['mapbox_place_id'])):?><p><strong>Mapbox ID:</strong> <?php echo craftcrawl_admin_escape($l['mapbox_place_id']);?></p><?php endif;?><?php if($is_suggestion&&!empty($l['matched_location_id'])):?><p><strong>Matched location:</strong> #<?php echo craftcrawl_admin_escape($l['matched_location_id']);?></p><?php endif;?></div><form class="admin-recovery-review-form" method="POST"><?php echo craftcrawl_csrf_input();?><?php if($is_suggestion):?><input type="hidden" name="suggestion_id" value="<?php echo $l['suggestion_id'];?>"><?php else:?><input type="hidden" name="location_id" value="<?php echo $l['location_id'];?>"><?php endif;?><textarea name="admin_notes" placeholder="Admin notes"><?php echo craftcrawl_admin_escape($l['adminNotes']??'');?></textarea><div class="admin-recovery-review-actions"><?php if($is_suggestion):?><button name="form_action" value="save_suggestion_notes">Save notes</button><button name="form_action" value="restore_suggestion">Move back to pending</button><?php else:?><button name="form_action" value="save_location_notes">Save notes</button><?php if($l['review_status']==='hidden'):?><button name="form_action" value="unhide_location">Restore as unclaimed</button><?php else:?><button name="form_action" value="hide_location">Hide</button><?php endif;?><?php endif;?></div></form></article><?php endwhile;?></section>
